+<dict>
+    <key>ProductBuildVersion</key>
+    <string>23A344</string>
+    <key>ProductName</key>
+    <string>macOS</string>
+    <key>ProductUserVisibleVersion</key>
+    <string>14.0</string>
+</dict>
+</plist>
+"#;
+
+        let version: SoftwareVersion = plist::from_bytes(plist.as_bytes()).unwrap();
